{
  "command": "node -e '
const fs = require("fs");
const src = fs.readFileSync("lib/api-key-accounts.ts", "utf8");
const m = src.match(/const MANAGED_ACCOUNT_PROVIDERS = new Set<string>\(\[([^\]]+)\]\)/);
if (!m) { console.error("FAIL: allowlist not found"); process.exit(1); }
const providers = [...m[1].matchAll(/"([^"]+)"/g)].map(x => x[1]);
console.log("MANAGED_ACCOUNT_PROVIDERS =", providers);
const has = (p) => providers.includes(p);
const checks = [
  ["xai", true],
  ["opencode-go", true],
  ["openai", false],
  ["anthropic", false],
];
let failed = 0;
for (const [p, expected] of checks) {
  const actual = has(p);
  console.log(`${actual === expected ? "PASS" : "FAIL"} managed(${p}) => ${actual} expected ${expected}`);
  if (actual !== expected) failed++;
}
const fnOk = /export function isManagedApiKeyProvider\(provider: string\): boolean \{\s*return MANAGED_ACCOUNT_PROVIDERS\.has\(provider\);\s*\}/.test(src);
console.log(fnOk ? "PASS isManagedApiKeyProvider delegates to allowlist" : "FAIL isManagedApiKeyProvider body unexpected");
if (!fnOk) failed++;
const stale = /v1 only opencode-go|v1: only opencode-go|v1: opencode-go only/.test(src);
console.log(!stale ? "PASS no stale v1-only-opencode-go comments" : "FAIL stale comments remain");
if (stale) failed++;
if (failed) process.exit(1);
console.log("XAI-01 focused managed-provider checks passed.");
'"
}

